// STAFF — on-demand PortConnect container-visits refresh for a booking.
import "jsr:@supabase/functions-js/edge-runtime.d.ts"
import { cors, json, requireStaff } from "../_shared/portalCommon.ts"
import { refreshBookingPortConnect } from "../_shared/portconnectRefreshRun.ts"

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: cors })
  if (req.method !== "POST") return json({ error: "method not allowed" }, 405)

  try {
    const gate = await requireStaff(req)
    if (!gate.ok) return gate.response

    const body = await req.json().catch(() => ({}))
    const bookingId = typeof body?.booking_id === "string" ? body.booking_id.trim() : ""
    if (!bookingId) return json({ error: "booking_id is required" }, 400)

    const apiKey = Deno.env.get("PORTCONNECT_API_KEY") ?? ""
    if (!apiKey) return json({ error: "PORTCONNECT_API_KEY not configured" }, 500)

    const summary = await refreshBookingPortConnect(gate.db, apiKey, bookingId)
    if (!summary.ok) {
      return json({ error: summary.error ?? "Refresh failed", ...summary }, 502)
    }
    return json(summary)
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    return json({ error: message }, 500)
  }
})

import { createClient, type SupabaseClient } from "jsr:@supabase/supabase-js@2";

export const cors = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

export const json = (body: unknown, status = 200) =>
  new Response(JSON.stringify(body), {
    status,
    headers: { ...cors, "Content-Type": "application/json" },
  });

export async function requireStaff(req: Request): Promise<
  { ok: true; staffId: string; db: SupabaseClient } | { ok: false; response: Response }
> {
  const authHeader = req.headers.get("Authorization") ?? "";
  const url = Deno.env.get("SUPABASE_URL")!;
  const anon = Deno.env.get("SUPABASE_ANON_KEY")!;
  const service = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

  const userClient = createClient(url, anon, { global: { headers: { Authorization: authHeader } } });
  const { data: ures } = await userClient.auth.getUser();
  if (!ures?.user) return { ok: false, response: json({ error: "unauthorized" }, 401) };

  const { data: staff } = await userClient
    .from("staff_users")
    .select("user_id")
    .eq("user_id", ures.user.id)
    .maybeSingle();
  if (!staff) return { ok: false, response: json({ error: "forbidden" }, 403) };

  return { ok: true, staffId: ures.user.id, db: createClient(url, service) };
}

export function serviceClient(): SupabaseClient {
  return createClient(Deno.env.get("SUPABASE_URL")!, Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!);
}

export function normalizeEmail(email: unknown): string | null {
  if (typeof email !== "string") return null;
  const clean = email.trim().toLowerCase();
  return clean.includes("@") ? clean : null;
}

export const MIN_PASSWORD_LENGTH = 8;

/** Returns an error message, or null if the password meets minimum length. */
export function validatePassword(password: string): string | null {
  if (password.length < MIN_PASSWORD_LENGTH) {
    return `password must be at least ${MIN_PASSWORD_LENGTH} characters`;
  }
  return null;
}

export function generateToken(): string {
  const bytes = new Uint8Array(32);
  crypto.getRandomValues(bytes);
  const b64 = btoa(String.fromCharCode(...bytes));
  return b64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

export function portalSetPasswordLink(token: string): string {
  const base = (Deno.env.get("PORTAL_PUBLIC_BASE_URL") ?? "").replace(/\/$/, "");
  if (!base) throw new Error("PORTAL_PUBLIC_BASE_URL not configured");
  return `${base}/portal/set-password?token=${encodeURIComponent(token)}`;
}

export async function findAuthUserIdByEmail(
  admin: SupabaseClient,
  email: string,
): Promise<string | null> {
  let page = 1;
  while (true) {
    const { data, error } = await admin.auth.admin.listUsers({ page, perPage: 1000 });
    if (error || !data?.users?.length) return null;
    const hit = data.users.find((u) => (u.email ?? "").toLowerCase() === email);
    if (hit) return hit.id;
    if (data.users.length < 1000) return null;
    page += 1;
  }
}

export async function resolveAuthUserId(
  admin: SupabaseClient,
  email: string,
): Promise<{ userId: string; created: boolean } | { error: string }> {
  const existingId = await findAuthUserIdByEmail(admin, email);
  if (existingId) return { userId: existingId, created: false };

  const throwaway = generateToken();
  const { data, error } = await admin.auth.admin.createUser({
    email,
    email_confirm: true,
    password: throwaway,
  });
  if (error) {
    const retryId = await findAuthUserIdByEmail(admin, email);
    if (retryId) return { userId: retryId, created: false };
    return { error: error.message };
  }
  if (!data.user) return { error: "create user failed" };
  return { userId: data.user.id, created: true };
}

export async function issueInviteToken(
  db: SupabaseClient,
  opts: { userId: string; accountId: string; staffId: string },
): Promise<{ token: string; expiresAt: string; link: string }> {
  await db
    .from("portal_invite_tokens")
    .update({ used_at: new Date().toISOString() })
    .eq("user_id", opts.userId)
    .is("used_at", null);

  const token = generateToken();
  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
  const { error } = await db.from("portal_invite_tokens").insert({
    token,
    user_id: opts.userId,
    account_id: opts.accountId,
    expires_at: expiresAt,
    created_by: opts.staffId,
  });
  if (error) throw new Error(error.message);
  return { token, expiresAt, link: portalSetPasswordLink(token) };
}

import type { SupabaseClient } from "jsr:@supabase/supabase-js@2"
import type { JsonRecord } from "./portconnectClient.ts"
import { fetchContainerVisitsImport } from "./portconnectClient.ts"
import {
  bookingPatchFromVisit,
  countChangedFields,
  deriveRefreshEvents,
  type DerivedRefreshEvent,
} from "./portconnectVisitDiff.ts"
import {
  mapVisitToContainerRow,
  timestampsFromStored,
  timestampsFromVisit,
} from "./portconnectVisitMap.ts"
import { mergeContainerTrackingRow } from "./portconnectVisitMerge.ts"

export type RefreshSummary = {
  ok: boolean
  containers_found: number
  fields_changed: number
  events_written: number
  containers_not_recognised: string[]
  last_refreshed_at: string
  error?: string
}

function pickImportVisit(visits: JsonRecord[]): JsonRecord | null {
  if (!visits.length) return null
  const imports = visits.filter((v) => {
    const cat = String(v.category ?? v.Category ?? "").toUpperCase()
    return !cat || cat === "IMPORT"
  })
  return imports[0] ?? visits[0]
}

function parseOverrides(raw: unknown): Record<string, boolean> {
  if (!raw || typeof raw !== "object") return {}
  const out: Record<string, boolean> = {}
  for (const [k, v] of Object.entries(raw as Record<string, unknown>)) {
    if (v) out[k] = true
  }
  return out
}

async function eventExists(
  db: SupabaseClient,
  bookingId: string,
  containerNo: string,
  event: DerivedRefreshEvent,
): Promise<boolean> {
  const { data } = await db
    .from("tracking_events")
    .select("id")
    .eq("booking_id", bookingId)
    .eq("container_no", containerNo)
    .eq("event_type_code", event.event_type_code)
    .eq("event_datetime", event.event_datetime)
    .eq("source", "portconnect")
    .maybeSingle()
  return Boolean(data)
}

async function insertEvent(
  db: SupabaseClient,
  bookingId: string,
  containerNo: string,
  event: DerivedRefreshEvent,
  visit: JsonRecord,
): Promise<boolean> {
  if (await eventExists(db, bookingId, containerNo, event)) return false
  const { error } = await db.from("tracking_events").insert({
    booking_id: bookingId,
    container_no: containerNo,
    event_type_code: event.event_type_code,
    event_datetime: event.event_datetime,
    event_value: event.event_value,
    event_value2: event.event_value2,
    partner_port_code: event.partner_port_code,
    container_visit_id: event.container_visit_id,
    is_estimated: event.is_estimated,
    source: "portconnect",
    raw: visit,
  })
  if (error) throw new Error(error.message)
  return true
}

async function logSync(
  db: SupabaseClient,
  row: Record<string, unknown>,
): Promise<void> {
  await db.from("portconnect_sync_log").insert(row)
}

export async function refreshBookingPortConnect(
  db: SupabaseClient,
  apiKey: string,
  bookingId: string,
): Promise<RefreshSummary> {
  const ranAt = new Date().toISOString()
  let containersFound = 0
  let fieldsChanged = 0
  let eventsWritten = 0
  const notRecognised: string[] = []

  const [{ data: containers }, { data: booking }] = await Promise.all([
    db.from("booking_containers").select("container_no").eq("booking_id", bookingId).order("sort_order"),
    db.from("bookings").select("field_overrides, last_free_day").eq("id", bookingId).maybeSingle(),
  ])

  const containerNos = [...new Set(
    (containers ?? [])
      .map((c) => String(c.container_no ?? "").trim().toUpperCase())
      .filter(Boolean),
  )]

  if (!containerNos.length) {
    return {
      ok: false,
      containers_found: 0,
      fields_changed: 0,
      events_written: 0,
      containers_not_recognised: [],
      last_refreshed_at: ranAt,
      error: "No containers on this booking",
    }
  }

  const overrides = parseOverrides(booking?.field_overrides)
  const bookingPatch: Record<string, unknown> = {}

  for (const containerNo of containerNos) {
    const fetchResult = await fetchContainerVisitsImport(apiKey, containerNo)

    if (fetchResult.status === 401) {
      const msg = fetchResult.message ?? "PortConnect API key rejected (401)"
      await logSync(db, {
        booking_id: bookingId, container_no: containerNo, status: "error",
        http_status: 401, error: msg, fields_changed: 0, events_written: 0, ran_at: ranAt,
      })
      return { ok: false, containers_found: containersFound, fields_changed: fieldsChanged,
        events_written: eventsWritten, containers_not_recognised: notRecognised,
        last_refreshed_at: ranAt, error: msg }
    }
    if (fetchResult.status === 403) {
      const msg = fetchResult.message ?? "PortConnect access forbidden (403)"
      await logSync(db, {
        booking_id: bookingId, container_no: containerNo, status: "error",
        http_status: 403, error: msg, fields_changed: 0, events_written: 0, ran_at: ranAt,
      })
      return { ok: false, containers_found: containersFound, fields_changed: fieldsChanged,
        events_written: eventsWritten, containers_not_recognised: notRecognised,
        last_refreshed_at: ranAt, error: msg }
    }
    if (fetchResult.status === 429) {
      const msg = fetchResult.message ?? "PortConnect rate limit exceeded (429)"
      await logSync(db, {
        booking_id: bookingId, container_no: containerNo, status: "error",
        http_status: 429, error: msg, fields_changed: 0, events_written: 0, ran_at: ranAt,
      })
      return { ok: false, containers_found: containersFound, fields_changed: fieldsChanged,
        events_written: eventsWritten, containers_not_recognised: notRecognised,
        last_refreshed_at: ranAt, error: msg }
    }
    if (fetchResult.status === 404 || !fetchResult.data?.length) {
      notRecognised.push(containerNo)
      await logSync(db, {
        booking_id: bookingId, container_no: containerNo, status: "not_found",
        http_status: fetchResult.status, error: fetchResult.message ?? "Container not recognised",
        fields_changed: 0, events_written: 0, ran_at: ranAt,
      })
      continue
    }
    if (fetchResult.status !== 200) {
      const msg = fetchResult.message ?? `PortConnect error (${fetchResult.status})`
      await logSync(db, {
        booking_id: bookingId, container_no: containerNo, status: "error",
        http_status: fetchResult.status, error: msg, fields_changed: 0, events_written: 0, ran_at: ranAt,
      })
      return { ok: false, containers_found: containersFound, fields_changed: fieldsChanged,
        events_written: eventsWritten, containers_not_recognised: notRecognised,
        last_refreshed_at: ranAt, error: msg }
    }

    const visits = fetchResult.data as JsonRecord[]
    const visit = pickImportVisit(visits)
    if (!visit) {
      notRecognised.push(containerNo)
      continue
    }

    containersFound += 1

    const { data: existingRow } = await db
      .from("container_tracking")
      .select("*")
      .eq("booking_id", bookingId)
      .eq("container_no", containerNo)
      .maybeSingle()

    const before = timestampsFromStored(existingRow as Record<string, unknown> | null)
    const after = timestampsFromVisit(visit)
    const changed = countChangedFields(before, after)
    fieldsChanged += changed

    const mapped = mapVisitToContainerRow(visit, bookingId, containerNo)
    const row = mergeContainerTrackingRow(
      mapped,
      existingRow as Record<string, unknown> | null,
    )
    const { error: upsertErr } = await db.from("container_tracking").upsert(row, {
      onConflict: "booking_id,container_no",
    })
    if (upsertErr) throw new Error(upsertErr.message)

    const events = deriveRefreshEvents(visit, before, after)
    let containerEvents = 0
    for (const ev of events) {
      const inserted = await insertEvent(db, bookingId, containerNo, ev, visit)
      if (inserted) {
        containerEvents += 1
        eventsWritten += 1
      }
    }

    const visitPatch = bookingPatchFromVisit(visit, after, overrides)
    for (const [k, v] of Object.entries(visitPatch)) {
      if (!overrides[k]) bookingPatch[k] = v
    }

    await logSync(db, {
      booking_id: bookingId,
      container_no: containerNo,
      container_visit_id: row.container_visit_id ?? null,
      status: "ok",
      http_status: 200,
      error: null,
      fields_changed: changed,
      events_written: containerEvents,
      ran_at: ranAt,
    })
  }

  if (Object.keys(bookingPatch).length) {
    await db.from("bookings").update(bookingPatch).eq("id", bookingId)
  }

  await db.from("booking_tracking").upsert({
    booking_id: bookingId,
    last_portconnect_sync: ranAt,
    portconnect_error: notRecognised.length
      ? `Not recognised: ${notRecognised.join(", ")}`
      : null,
  }, { onConflict: "booking_id" })

  return {
    ok: true,
    containers_found: containersFound,
    fields_changed: fieldsChanged,
    events_written: eventsWritten,
    containers_not_recognised: notRecognised,
    last_refreshed_at: ranAt,
  }
}

export type JsonRecord = Record<string, unknown>

const API_BASE = "https://api.portconnect.io"

export function webhookUri(): string {
  const base = Deno.env.get("SUPABASE_URL")?.replace(/\/$/, "")
  if (!base) throw new Error("SUPABASE_URL not configured")
  return `${base}/functions/v1/portconnect-webhook`
}

export function portconnectHeaders(apiKey: string): HeadersInit {
  return {
    Accept: "application/json",
    "Content-Type": "application/json",
    "Ocp-Apim-Subscription-Key": apiKey,
  }
}

function fieldMap(obj: JsonRecord): Map<string, unknown> {
  const map = new Map<string, unknown>()
  for (const [k, v] of Object.entries(obj)) map.set(k.toLowerCase(), v)
  return map
}

export function pcField(obj: JsonRecord, ...names: string[]): unknown {
  const map = fieldMap(obj)
  for (const name of names) {
    const hit = map.get(name.toLowerCase())
    if (hit !== undefined && hit !== null && hit !== "") return hit
  }
  return null
}

export function chunk<T>(items: T[], size: number): T[][] {
  const out: T[][] = []
  for (let i = 0; i < items.length; i += size) out.push(items.slice(i, i + size))
  return out
}

export function expiresInDays(days: number): string {
  return new Date(Date.now() + days * 24 * 60 * 60 * 1000).toISOString()
}

export type SubscribeContainerResult = {
  subscriptionId: number
  containerNumber: string
  expiresAt: string | null
}

export async function portconnectSubscribeChunk(
  apiKey: string,
  webhookToken: string,
  bookingId: string,
  containerNumbers: string[],
): Promise<SubscribeContainerResult[]> {
  const body = {
    containers: containerNumbers.map((containerNumber) => ({
      containerNumber,
      userDefinedReference: bookingId,
    })),
    webhookURI: webhookUri(),
    webhookToken,
    portCode: "ALL",
    category: "IMPORT",
    eventTypeCodes: ["ALL"],
    facilityCode: null,
  }

  const res = await fetch(`${API_BASE}/v2/subscriptions`, {
    method: "POST",
    headers: portconnectHeaders(apiKey),
    body: JSON.stringify(body),
  })

  const data = (await res.json().catch(() => ({}))) as JsonRecord
  if (!res.ok) {
    const msg = String(pcField(data, "message", "title", "error") ?? res.statusText)
    throw new Error(`PortConnect subscribe failed (${res.status}): ${msg}`)
  }

  const subscriptionId = Number(pcField(data, "subscriptionId"))
  if (!Number.isFinite(subscriptionId)) {
    throw new Error("PortConnect subscribe response missing subscriptionId")
  }

  const containers = pcField(data, "containers")
  if (!Array.isArray(containers)) {
    return containerNumbers.map((containerNumber) => ({
      subscriptionId,
      containerNumber,
      expiresAt: expiresInDays(90),
    }))
  }

  return containers.map((row) => {
    const rec = row as JsonRecord
    const containerNumber = String(pcField(rec, "containerNumber") ?? "")
    const expiresAt = pcField(rec, "expirationDatetime") as string | null
    return {
      subscriptionId,
      containerNumber,
      expiresAt: expiresAt ?? expiresInDays(90),
    }
  }).filter((r) => r.containerNumber)
}

export async function portconnectDeleteContainer(
  apiKey: string,
  subscriptionId: number,
  containerNumber: string,
): Promise<void> {
  const encoded = encodeURIComponent(containerNumber)
  const res = await fetch(
    `${API_BASE}/v2/subscriptions/${subscriptionId}/containers/${encoded}`,
    { method: "DELETE", headers: portconnectHeaders(apiKey) },
  )
  if (res.status === 204 || res.ok) return
  const data = (await res.json().catch(() => ({}))) as JsonRecord
  const msg = String(pcField(data, "message", "title", "error") ?? res.statusText)
  throw new Error(`PortConnect unsubscribe failed (${res.status}): ${msg}`)
}

export type PortConnectFetchResult = {
  status: number
  data: JsonRecord | JsonRecord[] | null
  message: string | null
}

export async function fetchContainerVisitsImport(
  apiKey: string,
  containerNumber: string,
): Promise<PortConnectFetchResult> {
  const url = new URL(`${API_BASE}/v1/container-visits`)
  url.searchParams.set("containerNumber", containerNumber)
  url.searchParams.set("category", "IMPORT")

  const res = await fetch(url.toString(), {
    headers: { Accept: "application/json", "Ocp-Apim-Subscription-Key": apiKey },
  })

  const text = await res.text()
  let parsed: unknown = null
  try {
    parsed = text ? JSON.parse(text) : null
  } catch {
    parsed = text
  }

  const obj = parsed && typeof parsed === "object" ? parsed as JsonRecord : null
  const message = obj
    ? String(pcField(obj, "message", "title", "error", "detail") ?? "")
    : typeof parsed === "string" ? parsed : null

  if (!res.ok) {
    return { status: res.status, data: obj, message: message || res.statusText }
  }

  if (Array.isArray(parsed)) {
    return { status: res.status, data: parsed as JsonRecord[], message: null }
  }
  if (obj && Array.isArray(obj.data)) {
    return { status: res.status, data: obj.data as JsonRecord[], message: null }
  }
  if (obj && Array.isArray(obj.value)) {
    return { status: res.status, data: obj.value as JsonRecord[], message: null }
  }
  if (obj) return { status: res.status, data: [obj], message: null }
  return { status: res.status, data: [], message: null }
}

import type { JsonRecord } from "./portconnectClient.ts"
import { pcField } from "./portconnectClient.ts"
import { isLytteltonPort, nzlytEstimatedClearances, partnerPortCode } from "./portconnectFields.ts"
import type { VisitTimestamps } from "./portconnectVisitMap.ts"

export type DerivedRefreshEvent = {
  event_type_code: string
  event_datetime: string
  event_value: string | null
  event_value2: string | null
  is_estimated: boolean
  partner_port_code: string | null
  container_visit_id: number | null
}

type FieldSpec = {
  key: keyof VisitTimestamps
  setType: string
  valueAsEventValue?: boolean
}

const FIELD_SPECS: FieldSpec[] = [
  { key: "inbound_ata", setType: "VESSELARRIVAL" },
  { key: "discharged_at", setType: "DISCHARGE" },
  { key: "customs_release_at", setType: "CUSTOMSRELEASE" },
  { key: "mpi_release_at", setType: "MPIRELEASE" },
  { key: "line_release_at", setType: "LOPRELEASE" },
  { key: "last_free_at", setType: "LFTCHANGED", valueAsEventValue: true },
  { key: "vbs_slot_at", setType: "VBSCHANGED", valueAsEventValue: true },
  { key: "gate_out_at", setType: "GATEOUT" },
  { key: "delivered_at", setType: "DELIVERED" },
]

const ESTIMATED_RELEASE_TYPES = new Set(["CUSTOMSRELEASE", "MPIRELEASE", "LOPRELEASE"])

function isoEqual(a: string | null, b: string | null): boolean {
  if (a === b) return true
  if (!a || !b) return false
  return new Date(a).getTime() === new Date(b).getTime()
}

function fieldChanged(prev: string | null, next: string | null): boolean {
  if (next == null && prev != null) return false
  return !isoEqual(prev, next)
}

function releaseIsEstimated(
  visit: JsonRecord,
  after: VisitTimestamps,
  setType: string,
): boolean {
  if (!ESTIMATED_RELEASE_TYPES.has(setType)) return false
  return nzlytEstimatedClearances(
    after.line_release_at,
    after.customs_release_at,
    after.mpi_release_at,
    partnerPortCode(visit),
  )
}

export function deriveRefreshEvents(
  visit: JsonRecord,
  before: VisitTimestamps,
  after: VisitTimestamps,
): DerivedRefreshEvent[] {
  const port = partnerPortCode(visit)
  const lyttelton = isLytteltonPort(port)
  const visitIdRaw = pcField(visit, "containerVisitId")
  const visitId = visitIdRaw != null ? Number(visitIdRaw) : null
  const out: DerivedRefreshEvent[] = []

  for (const spec of FIELD_SPECS) {
    const prev = before[spec.key]
    const next = after[spec.key]

    if (lyttelton && spec.key === "last_free_at" && !next) continue
    if (!fieldChanged(prev, next)) continue
    if (!next) continue

    out.push({
      event_type_code: spec.setType,
      event_datetime: next,
      event_value: spec.valueAsEventValue ? next : null,
      event_value2: null,
      is_estimated: releaseIsEstimated(visit, after, spec.setType),
      partner_port_code: port,
      container_visit_id: Number.isFinite(visitId) ? visitId : null,
    })
  }

  return out
}

export function countChangedFields(before: VisitTimestamps, after: VisitTimestamps): number {
  return FIELD_SPECS.filter((s) => fieldChanged(before[s.key], after[s.key])).length
}

export function bookingPatchFromVisit(
  visit: JsonRecord,
  after: VisitTimestamps,
  overrides: Record<string, boolean>,
): Record<string, unknown> {
  const patch: Record<string, unknown> = {}

  if (!overrides.discharge_date && after.discharged_at) {
    patch.discharge_date = after.discharged_at.slice(0, 10)
  }
  if (!overrides.swb_released && after.line_release_at) {
    patch.swb_released = true
  }
  if (!overrides.cleared && after.customs_release_at && after.mpi_release_at) {
    patch.cleared = true
  }
  if (!overrides.delivery_date) {
    const delivery = after.delivered_at ?? after.gate_out_at
    if (delivery) patch.delivery_date = delivery.slice(0, 10)
  }
  if (!overrides.last_free_day && after.last_free_at) {
    patch.last_free_day = after.last_free_at.slice(0, 10)
  }

  return patch
}

import type { JsonRecord } from "./portconnectClient.ts"
import { asIso, asText, visitField } from "./portconnectFields.ts"
import { normalizeIso6346Pill } from "./iso6346Normalize.ts"

export function hazardCountFromVisit(visit: JsonRecord): number {
  const raw = visitField(visit, "hazardCount", "hazard_count")
  const n = Number(raw)
  return Number.isFinite(n) && n > 0 ? Math.trunc(n) : 0
}

export function hazardsFromVisit(visit: JsonRecord): unknown {
  const hazards = visitField(visit, "hazards")
  return Array.isArray(hazards) ? hazards : []
}

function previousVisitId(visit: JsonRecord): number | null {
  const raw = visitField(visit, "previousContainerVisitId")
  if (raw == null) return null
  const n = Number(raw)
  return Number.isFinite(n) ? Math.trunc(n) : null
}

export function mapVisitToContainerRow(
  visit: JsonRecord,
  bookingId: string,
  containerNo: string,
): Record<string, unknown> {
  const visitId = visitField(visit, "containerVisitId")
  const isoType = asText(visitField(visit, "containerIsoTypeCode"))
  const isoDesc = asText(visitField(visit, "containerIsoTypeDescription"))
  const depotCode = asText(visitField(visit, "emptyReturnDepotCode"))
  const depotName = asText(visitField(visit, "emptyReturnDepotName"))

  return {
    booking_id: bookingId,
    container_no: containerNo,
    container_visit_id: visitId != null ? Number(visitId) : null,
    previous_container_visit_id: previousVisitId(visit),
    port_code: asText(visitField(visit, "portCode", "partnerPortCode")),
    iso_type: isoType,
    iso_desc: isoDesc,
    container_type: normalizeIso6346Pill(isoType, isoDesc),
    container_status: asText(visitField(visit, "containerStatus")),
    container_location: asText(visitField(visit, "containerLocation")),
    booking_reference: asText(visitField(visit, "bookingReference")),
    load_port_name: asText(visitField(visit, "loadPortName")),
    discharge_port_name: asText(visitField(visit, "dischargePortName")),
    operator_code: asText(visitField(visit, "containerOperatorCode")),
    operator_name: asText(visitField(visit, "containerOperatorName")),
    operator_voyage_id: asText(visitField(visit, "containerOperatorVoyageId")),
    inbound_vessel_name: asText(visitField(visit, "inboundVesselName")),
    inbound_vessel_ref: asText(visitField(visit, "inboundVesselRef")),
    inbound_eta: asIso(visitField(visit, "inboundVesselPublishedArrivalDatetime")),
    inbound_ata: asIso(visitField(visit, "inboundVesselActualArrivalDatetime", "seaPortArrivalDatetime")),
    discharged_at: asIso(visitField(visit, "dischargedDatetime")),
    delivered_at: asIso(visitField(visit, "deliveredDatetime")),
    line_release_at: asIso(visitField(visit, "lineReleaseDatetime")),
    customs_release_at: asIso(visitField(visit, "customsReleaseDatetime")),
    mpi_release_at: asIso(visitField(visit, "mpiReleaseDatetime")),
    gate_out_at: asIso(visitField(visit, "seaPortGateOutDateTime", "inlandPortGateOutDateTime")),
    vbs_slot_at: asIso(visitField(visit, "vbsSlotDatetime")),
    last_free_at: asIso(visitField(visit, "lastFreeDatetime")),
    power_last_free_at: asIso(visitField(visit, "packedOffPowerDatetime")),
    empty_return_depot_code: depotCode,
    empty_return_depot_name: depotName,
    empty_return_depot: depotName ?? depotCode,
    security_check: asText(visitField(visit, "securityCheck")),
    stops: visitField(visit, "stops") ?? null,
    hazards: hazardsFromVisit(visit),
    hazard_count: hazardCountFromVisit(visit),
    express_pin_status: asText(visitField(visit, "expressPinStatus")),
    portconnect_last_updated: asIso(visitField(visit, "lastUpdated")),
    source: "portconnect",
    updated_at: new Date().toISOString(),
    raw: visit,
  }
}

export type VisitTimestamps = {
  inbound_ata: string | null
  discharged_at: string | null
  customs_release_at: string | null
  mpi_release_at: string | null
  line_release_at: string | null
  last_free_at: string | null
  vbs_slot_at: string | null
  gate_out_at: string | null
  delivered_at: string | null
}

export function timestampsFromVisit(visit: JsonRecord): VisitTimestamps {
  const row = mapVisitToContainerRow(visit, "", "")
  return {
    inbound_ata: row.inbound_ata as string | null,
    discharged_at: row.discharged_at as string | null,
    customs_release_at: row.customs_release_at as string | null,
    mpi_release_at: row.mpi_release_at as string | null,
    line_release_at: row.line_release_at as string | null,
    last_free_at: row.last_free_at as string | null,
    vbs_slot_at: row.vbs_slot_at as string | null,
    gate_out_at: row.gate_out_at as string | null,
    delivered_at: row.delivered_at as string | null,
  }
}

export function timestampsFromStored(row: Record<string, unknown> | null): VisitTimestamps {
  if (!row) {
    return {
      inbound_ata: null, discharged_at: null, customs_release_at: null,
      mpi_release_at: null, line_release_at: null, last_free_at: null,
      vbs_slot_at: null, gate_out_at: null, delivered_at: null,
    }
  }
  return {
    inbound_ata: asIso(row.inbound_ata),
    discharged_at: asIso(row.discharged_at),
    customs_release_at: asIso(row.customs_release_at),
    mpi_release_at: asIso(row.mpi_release_at),
    line_release_at: asIso(row.line_release_at),
    last_free_at: asIso(row.last_free_at),
    vbs_slot_at: asIso(row.vbs_slot_at),
    gate_out_at: asIso(row.gate_out_at),
    delivered_at: asIso(row.delivered_at),
  }
}

import type { JsonRecord } from "./portconnectClient.ts"
import { pcField } from "./portconnectClient.ts"

export function asText(value: unknown): string | null {
  if (value == null) return null
  const text = String(value).trim()
  return text || null
}

export function asIso(value: unknown): string | null {
  const text = asText(value)
  if (!text) return null
  const d = new Date(text)
  return Number.isNaN(d.getTime()) ? null : d.toISOString()
}

export function visitField(visit: JsonRecord, ...names: string[]): unknown {
  return pcField(visit, ...names)
}

export function toDateOnly(iso: string): string {
  return iso.slice(0, 10)
}

export function partnerPortCode(visit: JsonRecord): string | null {
  return asText(visitField(visit, "partnerPortCode", "portCode"))
}

export function isLytteltonPort(code: string | null | undefined): boolean {
  if (!code) return false
  const u = code.trim().toUpperCase()
  return u === "NZLYT" || u.includes("LYTTELTON")
}

export function sameInstant(a: string | null, b: string | null): boolean {
  if (!a || !b) return false
  const da = new Date(a).getTime()
  const db = new Date(b).getTime()
  if (Number.isNaN(da) || Number.isNaN(db)) return a === b
  return da === db
}

export function nzlytEstimatedClearances(
  lineRelease: string | null,
  customsRelease: string | null,
  mpiRelease: string | null,
  partnerPort: string | null,
): boolean {
  if (!isLytteltonPort(partnerPort)) return false
  if (!lineRelease || !customsRelease || !mpiRelease) return false
  return sameInstant(lineRelease, customsRelease) && sameInstant(customsRelease, mpiRelease)
}

/** Deno copy — keep in sync with src/features/importSea/iso6346Normalize.ts */

export type IsoPillKind = "G" | "H" | "R"

const LENGTH_TO_SIZE: Record<string, string> = {
  "20": "20", "22": "20", "25": "20",
  "42": "40", "45": "40",
  "L2": "45", "L5": "45",
}

const NUMERIC_TYPE_KIND: Record<string, IsoPillKind> = {
  "00": "G", "01": "G", "02": "G", "03": "G", "04": "G", "05": "G",
  "10": "G", "11": "G", "12": "G", "13": "G", "14": "G", "15": "G",
  "20": "G", "21": "G", "22": "G", "23": "G", "24": "G", "25": "G",
  "30": "R", "31": "R", "32": "R", "33": "R", "34": "R", "35": "R",
  "40": "H", "41": "H", "42": "H", "43": "H", "44": "H", "45": "H",
}

const ALPHA_TYPE_KIND: Record<string, IsoPillKind> = {
  G: "G", U: "G", P: "G", V: "G",
  R: "R", H: "H",
}

function sizeFromLengthCode(code: string): string | null {
  const u = code.toUpperCase()
  if (LENGTH_TO_SIZE[u]) return LENGTH_TO_SIZE[u]
  if (/^2/.test(u)) return "20"
  if (/^4/.test(u)) return "40"
  if (/^L/.test(u)) return "45"
  return null
}

function kindFromDescription(desc: string): IsoPillKind | null {
  const u = desc.toUpperCase()
  if (/REEF|REEFER|\bRF\b|\bRH\b|\bRT\b/.test(u)) return "R"
  if (/HIGH\s*CUBE|\bHC\b|\bHQ\b|\bHR\b/.test(u)) return "H"
  if (/GENERAL|DRY|STANDARD|\bGP\b|\bDC\b|\bDV\b/.test(u)) return "G"
  return null
}

function normalizeAlphanumeric(code: string): string | null {
  const m = code.match(/^(\d{2}|L\d)([A-Z])(\d)$/i)
  if (!m) return null
  const size = sizeFromLengthCode(m[1])
  if (!size) return null
  const letter = m[2].toUpperCase()
  const kind = ALPHA_TYPE_KIND[letter] ?? (letter === "H" ? "H" : "G")
  if (m[1].toUpperCase() === "45" && kind === "G") return `${size}H`
  return `${size}${kind}`
}

function normalizeNumeric(code: string): string | null {
  const m = code.match(/^(\d{2})(\d{2})$/)
  if (!m) return null
  const size = sizeFromLengthCode(m[1])
  if (!size) return null
  const kind = NUMERIC_TYPE_KIND[m[2]] ?? "G"
  if (m[1] === "45" && kind === "G") return `${size}H`
  return `${size}${kind}`
}

export function normalizeIso6346Pill(
  code: string | null | undefined,
  description?: string | null,
): string | null {
  const raw = code?.trim()
  if (!raw && !description?.trim()) return null

  const compact = raw?.replace(/[^A-Za-z0-9]/g, "").toUpperCase() ?? ""
  if (compact.length === 4) {
    const alpha = normalizeAlphanumeric(compact)
    if (alpha) return alpha
    const num = normalizeNumeric(compact)
    if (num) return num
  }

  const descKind = description?.trim() ? kindFromDescription(description) : null
  if (descKind && compact.length >= 2) {
    const size = sizeFromLengthCode(compact.slice(0, 2)) ?? compact.match(/^(20|40|45)/)?.[1]
    if (size) return `${size}${descKind}`
  }

  if (raw) return raw.toUpperCase()
  return null
}
